INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('tawheed', '⚠️ الشرك', 'medium', 'mc', 'الرُّقية الجائزة هي الخالية من الشرك، وما خصّها الدليل منها رقية:', '["العين والحُمَة", "الحُمّى فقط", "الصداع", "السحر"]'::jsonb, 0, '«العين والحُمَة» هو الموضع الصحيح الذي استدلّ به المؤلّف في هذا الموطن.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('tawheed', '📿 الرقى والتمائم', 'hard', 'mc', 'في حديث رويفع: من عقد لحيته أو تقلّد وتراً فإن محمداً ﷺ منه:', '["بريء", "قريب", "راضٍ", "شفيع"]'::jsonb, 0, '«بريء» هو ما ثبت في لفظ الحديث/الأثر كما أورده الكتاب.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('tawheed', '📿 الرقى والتمائم', 'easy', 'mc', 'قال سعيد بن جبير: من قطع تميمة من إنسان كان كـ:', '["عِدْل رقبة", "صيام شهر", "صدقة", "حجّة"]'::jsonb, 0, '«عِدْل رقبة» هو ما ثبت في لفظ الحديث/الأثر كما أورده الكتاب.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('tawheed', '📿 الرقى والتمائم', 'medium', 'mc', 'التمائم التي رخّص فيها بعض السلف هي المُعلّق من:', '["القرآن", "الفضة", "الخيوط", "الودع"]'::jsonb, 0, '«القرآن» هي الإجابة المطابقة لِما ورد في النصّ والمعنى المراد.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('tawheed', '📿 الرقى والتمائم', 'hard', 'mc', 'إبراهيم النخعي روي عنه كراهة التمائم كلها من القرآن و:', '["غير القرآن", "الذهب", "الجلد", "العظم"]'::jsonb, 0, '«غير القرآن» هو ما ثبت في لفظ الحديث/الأثر كما أورده الكتاب.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('tawheed', '📚 حديث القلادة والوتر (أبو بشير)', 'easy', 'mc', 'أرسل النبي ﷺ رسولاً في بعض أسفاره ألّا يبقى في رقبة بعير قلادة من وتر إلا:', '["قُطعت", "عُلّقت", "تُركت", "فُكّت"]'::jsonb, 0, '«قُطعت» هي الإجابة المطابقة لِما ورد في النصّ والمعنى المراد.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('tawheed', '📚 حديث القلادة والوتر (أبو بشير)', 'medium', 'mc', 'النهي عن القلائد في رقاب الإبل كان لأنهم يعتقدونها تدفع:', '["العين", "الجوع", "العطش", "التعب"]'::jsonb, 0, '«العين» هو ما ثبت في لفظ الحديث/الأثر كما أورده الكتاب.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('tawheed', '📚 حديث القلادة والوتر (أبو بشير)', 'hard', 'mc', 'تعليق الأوتار على الدوابّ حكمه في الباب:', '["التحريم", "الإباحة", "الكراهة", "الاستحباب"]'::jsonb, 0, 'الحكم الصحيح هو «التحريم»، كما قرّره النصّ الشرعيّ في الباب.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('tawheed', '📚 باب لا يُستشفع بالله على خلقه', 'easy', 'mc', 'سبّ الدهر يقع في الغالب عند نزول:', '["المصائب", "النعم", "الطاعات", "الأسفار"]'::jsonb, 0, '«المصائب» هو ما ثبت في لفظ الحديث/الأثر كما أورده الكتاب.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('tawheed', '📚 باب لا يُستشفع بالله على خلقه', 'medium', 'mc', 'من اعتقد أن الدهر فاعل مستقلّ مع الله فهو:؟', '["مشرك", "عاصٍ", "مبتدع", "جاهل"]'::jsonb, 0, '«مشرك» هي الإجابة المطابقة لِما ورد في النصّ والمعنى المراد.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('tawheed', '🕌 حق الله', 'hard', 'mc', 'في حديث معاذ إلى اليمن: أول ما يُدعون إليه شهادة أن لا إله إلا الله، فإن أطاعوا فأعلمهم أن الله فرض عليهم خمس صلوات في:', '["كل يوم وليلة", "كل أسبوع", "كل شهر", "رمضان"]'::jsonb, 0, '«كل يوم وليلة» هو ما ثبت في لفظ الحديث/الأثر كما أورده الكتاب.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('tawheed', '🕌 حق الله', 'easy', 'mc', 'ثم الزكاة تُؤخذ من أغنيائهم فتُرَدّ على:', '["فقرائهم", "الدولة", "المجاهدين", "المساجد"]'::jsonb, 0, '«فقرائهم» هي الإجابة المطابقة لِما ورد في النصّ والمعنى المراد.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('tawheed', '🕌 حق الله', 'medium', 'mc', 'حذّر النبي ﷺ معاذاً من أخذ كرائم الأموال، أي:', '["خيار المال", "رديء المال", "الزروع", "الأنعام فقط"]'::jsonb, 0, '«خيار المال» هي الإجابة المطابقة لِما ورد في النصّ والمعنى المراد.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('tawheed', '🕌 حق الله', 'hard', 'mc', 'يُستفاد من ترتيب التوحيد ثم الصلاة ثم الزكاة:', '["البدء بالأهمّ فالأهمّ", "التخيير", "التساوي", "تقديم الزكاة"]'::jsonb, 0, '«البدء بالأهمّ فالأهمّ» هي الإجابة المطابقة لِما ورد في النصّ والمعنى المراد.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'easy', 'mc', 'الأصول الثلاثة التي يُسأل عنها العبد هي:', '["معرفة الله ونبيه ودينه", "الصلاة والزكاة والصوم", "العلم والعمل والدعوة", "الإيمان والإسلام والإحسان"]'::jsonb, 0, '«معرفة الله ونبيه ودينه» هو ما ثبت في لفظ الحديث/الأثر كما أورده الكتاب.', 'ar');
