INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'hard', 'mc', 'معنى "لا إله" في كلمة التوحيد:', '["نفي جميع ما يُعبد من دون الله", "نفي وجود الله", "نفي الأنبياء", "نفي الملائكة"]'::jsonb, 0, '«نفي جميع ما يُعبد من دون الله» هو المعنى الصحيح المذكور في شرح الكتاب لهذه الكلمة/المصطلح.', 'ar');
