INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'hard', 'mc', 'الأصل الثاني من الأصول الثلاثة هو معرفة:', '["دين الإسلام بالأدلة", "الله", "النبي ﷺ", "القرآن"]'::jsonb, 0, '«دين الإسلام بالأدلة» هي الإجابة المطابقة لِما ورد في النصّ والمعنى المراد.', 'ar');
