INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'hard', 'mc', 'ركن الإحسان أن تعبد الله كأنك:', '["تراه", "تخافه", "ترجوه", "تحبه"]'::jsonb, 0, '«تراه» هي الإجابة المطابقة لِما ورد في النصّ والمعنى المراد.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'hard', 'mc', 'الدليل على نبوة محمد ﷺ سورة:', '["المدّثر", "الفاتحة", "الإخلاص", "العصر"]'::jsonb, 0, '«المدّثر» هو الموضع الصحيح الذي استدلّ به المؤلّف في هذا الموطن.', 'ar');
