INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'hard', 'mc', '"اقرأ باسم ربك الذي خلق" نزلت فجعلته:', '["نبياً", "رسولاً", "خاتماً", "إماماً"]'::jsonb, 0, '«نبياً» هي الإجابة المطابقة لِما ورد في النصّ والمعنى المراد.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('usool', '📖 الكتاب', 'hard', 'mc', '"يا أيها المدّثر قم فأنذر" نزلت فجعلته:', '["رسولاً", "نبياً", "خاتماً", "إماماً"]'::jsonb, 0, '«رسولاً» هي الإجابة المطابقة لِما ورد في النصّ والمعنى المراد.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '1- النية', 'easy', 'mc', 'حديث "إنما الأعمال بالنيات" يدل على أهمية:', '["النية والإخلاص", "المال", "النسب", "القوة"]'::jsonb, 0, '«النية والإخلاص» هو ما ثبت في لفظ الحديث/الأثر كما أورده الكتاب.', 'ar');
