INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '7- الدين النصيحة', 'medium', 'mc', '"الدين النصيحة" قالها النبي ﷺ، والنصيحة لـ:', '["الله وكتابه ورسوله وأئمة المسلمين وعامتهم", "الحاكم فقط", "العالم فقط", "النفس فقط"]'::jsonb, 0, '«الله وكتابه ورسوله وأئمة المسلمين وعامتهم» هو ما ثبت في لفظ الحديث/الأثر كما أورده الكتاب.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '1- النية', 'hard', 'mc', '"إنما الأعمال بالنيات" راويه:', '["عمر بن الخطاب", "ابن عمر", "أبو هريرة", "ابن مسعود"]'::jsonb, 0, '«عمر بن الخطاب» هي الإجابة المطابقة لِما ورد في النصّ والمعنى المراد.', 'ar');
