INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '1- النية', 'easy', 'mc', '"النية" في حديث الأعمال هي:', '["العزم على فعل العبادة تقرباً إلى الله وحمله البلق", "النطق باللسان", "حركة الجوارح", "الدعاء"]'::jsonb, 0, '«العزم على فعل العبادة تقرباً إلى الله وحمله البلق» هو ما ثبت في لفظ الحديث/الأثر كما أورده الكتاب.', 'ar');
