INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '📚 معاني الكلمات والفوائد', 'hard', 'mc', '"الإسلام" لغةً وشرعاً في حديث "بُني الإسلام":', '["الاستسلام لله بالتوحيد والانقياد له بالطاعة والبراءة من الشرك", "الإقرار فقط", "الصلاة فقط", "الدعاء"]'::jsonb, 0, '«الاستسلام لله بالتوحيد والانقياد له بالطاعة والبراءة من الشرك» هو ما ثبت في لفظ الحديث/الأثر كما أورده الكتاب.', 'ar');
