INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '📚 معاني الكلمات والفوائد', 'medium', 'mc', '"الصوم" شرعاً:', '["الإمساك عن الأكل والشرب والمفطرات من الفجر إلى الغروب تعبداً", "ترك الكلام", "ترك النوم", "الإمساك ليلاً"]'::jsonb, 0, '«الإمساك عن الأكل والشرب والمفطرات من الفجر إلى الغروب تعبداً» هي الإجابة المطابقة لِما ورد في النصّ والمعنى المراد.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '📚 معاني الكلمات والفوائد', 'hard', 'mc', '"الحج" شرعاً:', '["قصد بيت الله الحرام لأداء نسك مخصوص في وقت مخصوص", "زيارة المدينة", "الطواف فقط", "السعي فقط"]'::jsonb, 0, '«قصد بيت الله الحرام لأداء نسك مخصوص في وقت مخصوص» هي الإجابة المطابقة لِما ورد في النصّ والمعنى المراد.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '📚 معاني الكلمات والفوائد', 'easy', 'mc', 'معنى "آذنته بالحرب" في حديث الولاية:', '["أعلنت عليه الحرب", "سالمته", "نصحته", "تركته"]'::jsonb, 0, '«أعلنت عليه الحرب» هو المعنى الصحيح المذكور في شرح الكتاب لهذه الكلمة/المصطلح.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '📚 معاني الكلمات والفوائد', 'medium', 'mc', 'أحبّ ما يتقرب به العبد إلى الله بحسب حديث الولاية هو:', '["أداء الفرائض", "النوافل", "الذكر", "الدعاء"]'::jsonb, 0, '«أداء الفرائض» هو ما ثبت في لفظ الحديث/الأثر كما أورده الكتاب.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '📚 معاني الكلمات والفوائد', 'hard', 'mc', 'معنى "الخطأ" في حديث رفع الحرج:', '["ما يرتكبه الإنسان من العمل من غير عمد", "تعمّد الذنب", "النسيان", "الإكراه"]'::jsonb, 0, '«ما يرتكبه الإنسان من العمل من غير عمد» هو المعنى الصحيح المذكور في شرح الكتاب لهذه الكلمة/المصطلح.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '📚 معاني الكلمات والفوائد', 'easy', 'mc', 'معنى "النسيان" في حديث رفع الحرج:', '["ذهول القلب عن شيء معلوم من قبل", "ترك متعمّد", "الجهل", "الإكراه"]'::jsonb, 0, '«ذهول القلب عن شيء معلوم من قبل» هو المعنى الصحيح المذكور في شرح الكتاب لهذه الكلمة/المصطلح.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '📚 معاني الكلمات والفوائد', 'medium', 'mc', 'الأعذار الثلاثة التي رُفع بها الإثم في حديث ابن عباس هي:', '["الخطأ والنسيان والإكراه", "الجهل والفقر والمرض", "السفر والمرض والنوم", "الصغر والكبر والجنون"]'::jsonb, 0, '«الخطأ والنسيان والإكراه» هو ما ثبت في لفظ الحديث/الأثر كما أورده الكتاب.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '📚 متون إضافية', 'hard', 'mc', '"من حسن إسلام المرء":', '["تركه ما لا يعنيه", "صلاته", "صدقته", "صيامه"]'::jsonb, 0, '«تركه ما لا يعنيه» هي الإجابة المطابقة لِما ورد في النصّ والمعنى المراد.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '7- الدين النصيحة', 'medium', 'mc', '"الدين النصيحة"، قلنا لمن؟ قال: لله ولكتابه ولرسوله و:', '["أئمة المسلمين وعامتهم", "الملائكة", "الأنبياء", "الصحابة"]'::jsonb, 0, '«أئمة المسلمين وعامتهم» هو ما ثبت في لفظ الحديث/الأثر كما أورده الكتاب.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '📚 متون إضافية', 'hard', 'mc', '"إن الله طيّب لا يقبل إلا":', '["طيّباً", "حلالاً", "كثيراً", "قليلاً"]'::jsonb, 0, '«طيّباً» هي الإجابة المطابقة لِما ورد في النصّ والمعنى المراد.', 'ar');
INSERT INTO questions (book, chapter, level, type, question_text, options, correct_index, explanation, language) VALUES ('nawawi', '📚 متون إضافية', 'easy', 'mc', '"البر حسن الخلق، والإثم ما حاك في":', '["نفسك", "قلبك", "صدرك", "عقلك"]'::jsonb, 0, '«نفسك» هي الإجابة المطابقة لِما ورد في النصّ والمعنى المراد.', 'ar');